### B. Flow State Management
```typescript
interface FlowNode {
  id: string;
  type: string;
  position: { x: number; y: number };
  data: {
    label: string;
    config: Record<string, any>;
    executed?: boolean;
    error?: string;
  };
}

interface FlowEdge {
  id: string;
  source: string;
  target: string;
  label?: string; // 'yes', 'no', 'true', 'false'
  animated?: boolean;
}

interface AutomationFlow {
  id: string;
  name: string;
  nodes: FlowNode[];
  edges: FlowEdge[];
  triggers: string[];
  status: 'draft' | 'active' | 'paused';
  stats: { executed: number; conversion: number };
}
```

## 3. **Feature Implementation Priority**

### Phase 1: MVP (4-6 weeks)
- [ ] Drag-drop node editor
- [ ] Basic node types (Trigger, Action, Delay)
- [ ] Simple conditional logic
- [ ] Flow validation & testing
- [ ] REST API execution

```typescript
// Validation example
function validateFlow(flow: AutomationFlow): ValidationError[] {
  const errors: ValidationError[] = [];

  // Check triggers exist
  if (flow.triggers.length === 0) {
    errors.push({ type: 'NO_TRIGGER', severity: 'error' });
  }

  // Check all nodes connected
  const nodeIds = new Set(flow.nodes.map(n => n.id));
  flow.edges.forEach(edge => {
    if (!nodeIds.has(edge.source) || !nodeIds.has(edge.target)) {
      errors.push({ type: 'INVALID_CONNECTION', severity: 'error' });
    }
  });

  // Check dead ends
  const hasDeadEnds = flow.nodes.some(node => 
    !flow.edges.some(e => e.source === node.id)
  );
  if (hasDeadEnds) {
    errors.push({ type: 'DEAD_ENDS', severity: 'warning' });
  }

  return errors;
}
```
